export type CraftTag =
  | 'pottery'
  | 'weaving'
  | 'woodwork'
  | 'leather'
  | 'dyeing'
  | 'paper'
  | 'metal'
  | 'others';

export interface CraftLabelMap {
  pottery: string;
  weaving: string;
  woodwork: string;
  leather: string;
  dyeing: string;
  paper: string;
  metal: string;
  others: string;
}

export const CRAFT_LABELS: CraftLabelMap = {
  pottery: '陶艺',
  weaving: '编织',
  woodwork: '木工',
  leather: '皮具',
  dyeing: '染织',
  paper: '纸艺',
  metal: '金工',
  others: '其他',
};

export function craftLabel(craft: string): string {
  const map: CraftLabelMap = CRAFT_LABELS;
  return map[craft as CraftTag] ?? craft;
}

